using System.ComponentModel.DataAnnotations;

namespace CP2.Entities;

public class Categoria
{
    [Key]
    public int Id { get; set; }

    [Required(ErrorMessage = "Informe o nome da categoria")]
    [StringLength(100, MinimumLength = 3, ErrorMessage = "O nome deve conter entre 3 e 100 caracteres")]
    public string Nome { get; set; } = string.Empty;

    [StringLength(255)]
    public string? Descricao { get; set; }
}

using System.ComponentModel.DataAnnotations;
using System.ComponentModel.DataAnnotations.Schema;

namespace CP2.Entities;

[Table("TB_CATEGORIA")]
public class Categoria
{
    [Key]
    public int Id { get; set; }

    [Required(ErrorMessage = "Informe o nome da categoria")]
    [StringLength(100, MinimumLength = 3, ErrorMessage = "O nome deve conter entre 3 e 100 caracteres")]
    public string Nome { get; set; } = string.Empty;

    [StringLength(255)]
    public string? Descricao { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace CP2.Entities;

public class Produto
{
    [Key]
    public int Id { get; set;  }
    [Required(ErrorMessage = "Informe o nome do produto")]
    [StringLength(150,  MinimumLength = 3)]
    public string Nome { get; set; } = string.Empty;
    [Range(typeof(decimal), "0.01", "9999999999", ErrorMessage = "Preço deve ser superior que 0")]
    public decimal Preco { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace CP2.Entities;

public class Produto
{
    [Key]
    public int Id { get; set;  }
    [Required(ErrorMessage = "Informe o nome do produto")]
    [StringLength(150,  MinimumLength = 3)]
    public string Nome { get; set; } = string.Empty;
    [Range(0.01, 9999999999.0, ErrorMessage = "Preço deve ser superior que 0")]
    public decimal Preco { get; set; }
}
